mapper.select:
select index_code,industry_name,level,b.pct_change
from stock_list.industry_list as a inner join shenwan_daily.`${tradeDate}` as b on a.index_code = b.ts_code
where level = #{level};

select index_code,industry_name,level,b.pb
from stock_list.industry_list as a inner join shenwan_daily.`${tradeDate}` as b on a.index_code = b.ts_code
where level = #{level};

select industry_name_l1,industry_name_l2,industry_name_l3,index_code_l1 ,index_code_l2 ,index_code_l3,
       count(*) as ct,sum(total_mv) as mv,sum(amount) as amt,b.trade_date
from stock_list.industry_member as a
         left join common_daily.`20251201` as b on a.ts_code = b.ts_code where



        and 
        group by industry_name_l1 order by mv desc;


        and index_code_l1 = #{indexCode}
        and 
        group by industry_name_l3 order by industry_name_l2,mv desc


        and c.province = #{indexCode}
        and 
        group by industry_name_l1,industry_name_l2 order by industry_name_l1,mv desc




        and 
        order by mv desc;


        and index_code_l1 = #{indexCode}
        and 
        group by industry_name_l2 order by mv desc


        and c.province = #{indexCode}
        and 
        group by industry_name_l1 order by mv desc

select industry_name_l1,industry_name_l2,industry_name_l3,count(*) as all_ct,sum(total_mv) as all_mv,sum(amount) as all_amt
from stock_list.industry_member as a
left join common_daily.`20251201` as b on a.ts_code = b.ts_code


        where 
        group by industry_name_l1 order by all_mv desc;


        where 
        and index_code_l1 = #{indexCode}
        group by industry_name_l3 order by industry_name_l2,all_mv desc


        where 
        and c.province = #{indexCode}
        group by industry_name_l1,industry_name_l2 order by industry_name_l1,all_mv desc




        where 
        order by all_mv desc;


        where 
        and index_code_l1 = #{indexCode}
        group by industry_name_l2 order by all_mv desc


        where 
        and c.province = #{indexCode}
        group by industry_name_l1 order by all_mv desc

select c.province, case when count(distinct a.industry_name_l1) = 1 then max(a.industry_name_l1) else '' end as industry_name_l1 , case when count(distinct a.industry_name_l2) = 1 then max(a.industry_name_l2) else '' end as industry_name_l2 , case when count(distinct a.industry_name_l3) = 1 then max(a.industry_name_l3) else '' end as industry_name_l3 , index_code_l1 ,index_code_l2 ,index_code_l3 , count(*) as ct,sum(total_mv) as mv,sum(total_mv/pb) as asset,sum(total_mv/pe_ttm) as income,sum(total_mv/ps_ttm) as profit,sum(amount) as amt,trade_date,amount/total_mv as turnover from stock_list.industry_member as a left join common_daily.`20251201` as b on a.ts_code = b.ts_code left join stock_list.stock_company as c on b.ts_code = c.ts_code
where index_code_l1=#{indexCode}
where index_code_l2=#{indexCode}
where index_code_l3=#{indexCode}
group by c.province order by mv desc;

select a.trade_date ,a.close,a.open,a.high,a.low,a.pct_chg,a.amount,a.turnover_rate,a.pe_ttm,a.pb,b.north_money from daily_index.`000001` as a
inner join hsgt.hsgt_overview as b on a.trade_date = b.trade_date
order by a.trade_date asc;
